var $ = require('jquery');
var Container = require('../../../com/container/container');
var eventProxy = require('../../../core/eventproxy');

var Index = function(){};

Container._extend(Index, {
  _className : 'index',
  __filename: __filename,
  afterComplete: function(){
    Index.prototype._super.afterComplete.call(this);
    var _self = this;
    this.notices = $('.notices', this.el);
    eventProxy.on('toolbar.notices', function(err, data){
      var html = data.html;
      html = html.replace(/&quot;/g, '');
      var hash = localStorage.getItem('dxp_toolbar_notices');
      if(hash !== data.hash){
        localStorage.setItem('dxp_toolbar_notices', data.hash);
      }
      _self.notices.html(html);
      $('li>a', _self.notices).each(function(index, item){
        $(item).attr('target', '_blank');
      });
    });
  }
});

exports = module.exports = Index;